// Re-assert both ensures-foralls so their default triggers
// (`post1_self_.page_is_mapped`, `post2_self_.page_is_mapped`) are both
// "live" in the proof context. Without this, z3 instantiates each forall
// only on its own post-state and never lines the two runs up on the same p.
assert(forall|p: PagePtr|
    post1_self_.page_is_mapped(p) && p != target_ptr ==>
        post1_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post1_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));
assert(forall|p: PagePtr|
    post2_self_.page_is_mapped(p) && p != target_ptr ==>
        post2_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post2_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));

// Transitive spec-fn-level equalities: each post is pinned to pre by
// ensures, so the two posts agree on every observable spec projection.
assert(post1_self_.allocated_pages_4k() =~= post2_self_.allocated_pages_4k());
assert(post1_self_.allocated_pages_2m() =~= post2_self_.allocated_pages_2m());
assert(post1_self_.allocated_pages_1g() =~= post2_self_.allocated_pages_1g());
assert(post1_self_.page_mappings(target_ptr) =~= post2_self_.page_mappings(target_ptr));
assert(post1_self_.page_io_mappings(target_ptr) =~= post2_self_.page_io_mappings(target_ptr));

// Pointwise forall: for any p where both posts have p mapped (and p !=
// target_ptr), both page_mappings/page_io_mappings equal pre's, so they
// equal each other. Re-stating with this trigger pattern forces z3 to
// instantiate both ensures-foralls on the same p.
assert(forall|p: PagePtr|
    post1_self_.page_is_mapped(p) && post2_self_.page_is_mapped(p) && p != target_ptr ==>
        post1_self_.page_mappings(p) =~= post2_self_.page_mappings(p)
        && post1_self_.page_io_mappings(p) =~= post2_self_.page_io_mappings(p));

// Ghost-field equalities (these are the form det_..._equal actually
// compares for container_map_*). Both posts equal the same pre-derived
// expression by ensures, hence equal each other.
assert(post1_self_.container_map_4k@ =~= post2_self_.container_map_4k@);
assert(post1_self_.container_map_2m@ =~= post2_self_.container_map_2m@);
assert(post1_self_.container_map_1g@ =~= post2_self_.container_map_1g@);
